SELECT SUM(amount) FROM(
    SELECT concat('+',pay_amount) amount
    FROM app_pay_amount_record WHERE user_id = #{id} AND type = 1 AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
       UNION ALL
    SELECT concat('+',pay_amount) amount
    FROM app_pay_amount_record WHERE user_id = #{id} AND type = 2 AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
       UNION ALL
    SELECT concat('+',amount)amount
    FROM app_user_plus_royalty WHERE royalty_user_id = #{id} AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
       UNION ALL
    SELECT concat('+',settle_plus_amount) amount
    FROM app_settle_plus WHERE plus_id = #{id} AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
       UNION ALL
    SELECT concat('+',fixloss_user) amount
    FROM app_indent WHERE user_id = #{id} AND state = 6 AND DATE_FORMAT(creat_time,'%Y-%m') = #{operationMonth}
       UNION ALL
    SELECT concat('+',momey) amount
    FROM app_user_account_record WHERE user_id = user_id = #{id} AND type = 12 AND momey <> 0 AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
       UNION ALL
    SELECT concat('+',momey) amount
    FROM app_user_account_record WHERE user_id = user_id = #{id} AND type = 14  AND DATE_FORMAT(create_time,'%Y-%m') = #{operationMonth}
    ) t

SELECT id,user_id userId,video,statuse,reason,type,introduce,DATE_FORMAT(create_time,'%Y-%m-%d') createTime FROM app_accident_record WHERE type = 1
AND create_time BETWEEN #{beginTime} AND #{endTime}
AND user_id IN
#{users}
ORDER BY createTime DESC limit #{pagesize},20
